use std::collections::HashMap;

struct DataLoader {
    cache: HashMap<i32, String>,
}

impl DataLoader {
    fn new() -> Self {
        DataLoader { cache: HashMap::new() }
    }

    fn load(&mut self, key: i32) -> Result<String, &'static str> {
        if let Some(data) = self.cache.get(&key) {
            return Ok(data.clone());
        }

        let result = format!("Data for {}", key);
        self.cache.insert(key, result.clone());
        Ok(result)
    }

    fn batch_load(&mut self, keys: Vec<i32>) -> HashMap<i32, Result<String, &'static str>> {
        let mut results = HashMap::new();
        for key in keys {
            results.insert(key, self.load(key));
        }
        results
    }
}

fn main() {
    let mut loader = DataLoader::new();
    let input_keys = vec![101, 205, 101];
    let batch_results = loader.batch_load(input_keys);

    println!("--- Batch Loading Results ---n");
    for (key, result) in &batch_results {
        match result {
            Ok(data) => println!("Successfully loaded key {}: {}", key, data),
            Err(e) => println!("Failed to load key {}: {}", key, e),
        }
    }
}

use std::collections::HashMap;

struct ChessBoard {
    pieces: HashMap<String, String>,
}

impl ChessBoard {
    fn new() -> Self {
        ChessBoard { pieces: HashMap::new() }
    }

    fn place_piece(&mut self, piece_type: &str, location: &str) -> bool {
        if piece_type.is_empty() || location.is_empty() {
            return false;
        }
        self.pieces.insert(location.to_string(), piece_type.to_string());
        true
    }

    fn is_valid_move(&self, from: &str, to: &str) -> bool {
        if !self.pieces.contains_key(from) || self.pieces.contains_key(to) {
            return false;
        }
        match self.pieces.get(from).unwrap().chars().next().unwrap().to_ascii_uppercase()
        {
            'P' => { 
                if to.len() == 1 && !self.pieces.contains_key(to) {
                    true
                } else {
                    false
                }
            },
            _ => true
        }
    }
}

fn main() {
    let mut board = ChessBoard::new();
    board.place_piece("King", "a1");
    board.place_piece("Pawn", "h2");

    println!("Board initialized successfully.");

    if board.is_valid_move(&"a1", &"b1") {
        println!("Movement check passed for a1 to b1.");
    } else {
        println!("Movement check failed or is invalid.");
    }
}

