use std::collections::VecDeque;
use std::thread;
use std::time::{Duration, Instant};

struct MessageEvent {
    message_id: u32,
    payload: String,
}

struct SyncProcessor {
    local_queue: VecDeque<MessageEvent>,
    last_sync_time: Instant,
}

impl SyncProcessor {
    fn new() -> Self {
        SyncProcessor {
            local_queue: VecDeque::new(),
            last_sync_time: Instant::now().checked_sub(Duration::from_secs(1)).unwrap_or(Instant::now()),
        }
    }

    fn enqueue_incoming(&mut self, event: MessageEvent) {
        self.local_queue.push_back(event);
    }

    fn should_sync(&self) -> bool {
        self.last_sync_time.elapsed() >= Duration::from_secs(5)
    }

    fn process_background_tasks(&mut self) -> Result<(), &'static str> {
        if !self.should_sync() && !self.local_queue.is_empty(){
            return Err("Sync interval not met and queue is empty enough to skip.");
        }

        if self.local_queue.is_empty() && !self.should_sync() {
            println!("System idle, waiting for next trigger.");
            return Ok(());
        }

        let messages_to_process: VecDeque<MessageEvent> = self.local_queue.drain(..).collect();
        if messages_to_process.is_empty() {
            println!("No new events to process.");
            return Ok(());
        }

        let mut processed_count = 0;
        for event in messages_to_process {
            println!("Processing message ID {} for sync. Payload: {}", event.message_id, event.payload);
            processed_count += 1;
        }

        self.last_sync_time = Instant::now();
        Ok(())
    }
}

fn main() {
    let mut processor = SyncProcessor::new();
    processor.enqueue_incoming(MessageEvent { message_id: 101, payload: "Initial setup data".to_string() });
    processor.enqueue_incoming(MessageEvent { message_id: 102, payload: "Test event one".to_string() });

    for _i in 0..3 {
        thread::sleep(Duration::from_millis(500));
        match processor.process_background_tasks() {
            Ok(_) => println!("Background cycle finished successfully."),
            Err(e) => println!("Skipping background sync: {}", e),
        }
    }
}

use std::collections::HashSet;

struct SandboxProcessor {
    processed_count: usize,
}

impl SandboxProcessor {
    fn new() -> Self {
        SandboxProcessor { processed_count: 0 }
    }

    fn process_data(&mut self, data: &[u8]) -> Result<(), String> {
        if data.is_empty() {
            return Ok(()) 
        }

        let mut seen = HashSet::new();
        for chunk in data.iter().chain(std::iter::once(&0u8)).take(data.len() + 1) {
            if *chunk != 0 && !seen.contains(chunk) {
                seen.insert(*chunk);
            }
        }

        self.processed_count += 1;
        Ok(())
    }

    fn get_processed_count(&self) -> usize {
        self.processed_count
    }
}

fn main() {
    let mut processor = SandboxProcessor::new();

    let test_data1: [u8; 3] = [10, 20, 30];
    processor.process_data(&test_data1).unwrap();

    let test_data2: [u8; 1] = [99];
    processor.process_data(&test_data2).unwrap();

    println!("Successfully processed data, total runs: {}", processor.get_processed_count());
}
